// CORRECT: LIFO compensation constant + no saga on dispute (T611)
const COMPENSATION_STEPS_LIFO = ['REFUND_PAYMENT', 'RESTORE_INVENTORY'] as const;

async handlePaymentReversalRequested(event) {
  // LIFO: REFUND at index 0, RESTORE at index 1
  for (const step of COMPENSATION_STEPS_LIFO) {
    await this.sagaService.compensate(step, event.orderId);
  }
}

async handleDisputeInitiated(event) {
  // updateDocument ONLY — never deleteDocument (forensic evidence preserved)
  await this.db.updateDocument(event.escrowId, {
    status: 'DISPUTED',
    accessBlocked: true
  });
  // NO saga compensation triggered here
  await this.queue.enqueue('EscrowDisputed', { ... });
}

